const response = $('Search Bitcoin Questions').first().json;
const tweets = response.data || [];

// Filter to genuine questions
const questions = tweets.filter(t => {
  const text = t.text.toLowerCase();
  // Must contain a question mark or question words
  const isQuestion = text.includes('?') || text.includes('should i') || text.includes('what do you think') || text.includes('anyone know');
  // Exclude spam/promotional tweets
  const isSpam = text.includes('giveaway') || text.includes('airdrop') || text.includes('dm me') || text.includes('send me');
  return isQuestion && !isSpam;
});

// Limit to max 3 per run
const limited = questions.slice(0, 3);

if (limited.length === 0) {
  return [{ json: { skip: true, reason: 'No genuine Bitcoin questions found' } }];
}

return limited.map(t => ({
  json: {
    skip: false,
    tweetId: t.id,
    tweetText: t.text
  }
}));

